@page "/account/login"
@using Microsoft.AspNetCore.Identity
@layout sv_048f2f97722c40399fd2fc0fb61a3900.Components.Layout.MainLayout
@inject SignInManager<IdentityUser> SignInManager
@inject NavigationManager Navigation

<PageTitle>Login</PageTitle>

<div class="row justify-content-center mt-5">
    <div class="col-md-4">
        <h3>Login</h3>

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        <form method="post" @formname="login" @onsubmit="HandleLogin">
            <AntiforgeryToken />

            <div class="mb-3">
                <label class="form-label">Email</label>
                <InputText @bind-Value="email" class="form-control" />
            </div>

            <div class="mb-3">
                <label class="form-label">Password</label>
                <InputText @bind-Value="password" type="password" class="form-control" />
            </div>

            <button type="submit" class="btn btn-primary w-100">Sign In</button>
        </form>
    </div>
</div>

@code {
    [SupplyParameterFromForm] private string email { get; set; } = "";
    [SupplyParameterFromForm] private string password { get; set; } = "";
    [SupplyParameterFromQuery] private string? returnUrl { get; set; }

    private string? errorMessage;

    private async Task HandleLogin()
    {
        var result = await SignInManager.PasswordSignInAsync(email, password, isPersistent: false, lockoutOnFailure: false);
        if (result.Succeeded)
        {
            Navigation.NavigateTo(returnUrl ?? "/", forceLoad: true);
        }
        else
        {
            errorMessage = "Invalid email or password.";
        }
    }
}

@page "/admin/users"
@rendermode InteractiveServer
@attribute [Authorize(Roles = "Admin")]
@using Microsoft.AspNetCore.Identity
@inject UserManager<IdentityUser> UserManager

<PageTitle>User Administration</PageTitle>

<h3>User Administration</h3>

@if (users is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Email</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var (user, roles) in users)
            {
                <tr>
                    <td>@user.Email</td>
                    <td>@string.Join(", ", roles)</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<(IdentityUser User, IList<string> Roles)>? users;

    protected override async Task OnInitializedAsync()
    {
        var allUsers = UserManager.Users.ToList();
        var result = new List<(IdentityUser, IList<string>)>();
        foreach (var user in allUsers)
        {
            var roles = await UserManager.GetRolesAsync(user);
            result.Add((user, roles));
        }
        users = result;
    }
}

